class Projector {
  async handle(event) {
    switch (event.type) {
      case 'OrderCreated':
        await readDB.insert({ id: event.data.orderId, total: 0, items: [] })
        break
      case 'ItemAdded':
        const order = await readDB.find(event.data.orderId)
        order.items.push(event.data.item)
        order.total += event.data.item.price
        await readDB.update(order)
        break
    }
  }
}
